/* ==========================================================================
   Expand / Collapse toggle — detailed card content (M003/S02/T03)
   ==========================================================================
   Pattern:
   - <button class="card-expand-toggle" aria-expanded="false"> triggers JS
   - <div class="card-detail" hidden> holds the extra content
   - JS removes `hidden` and adds `.card-detail--expanded` on open
   ========================================================================== */

.card-expand-toggle {
  display: flex;
  align-items: center;
  gap: 0.35rem;
  margin: 0.75rem 0 0;
  padding: 0.3rem 0;
  background: none;
  border: none;
  border-top: 1px solid color-mix(in srgb, var(--accent-celeste) 25%, transparent);
  color: var(--accent-celeste);
  font-family: inherit;
  font-size: 0.8rem;
  font-weight: 600;
  letter-spacing: 0.03em;
  cursor: pointer;
  width: 100%;
  text-align: left;
  transition: color 0.15s ease, border-color 0.15s ease;
}

.card-expand-toggle:hover,
.card-expand-toggle:focus-visible {
  color: var(--gold);
  border-color: var(--gold);
  outline: none;
}

.card-expand-toggle:focus-visible {
  outline: 2px solid var(--gold);
  outline-offset: 2px;
}

.card-expand-toggle__icon {
  display: inline-block;
  font-size: 0.65rem;
  transition: transform 0.25s ease;
  transform-origin: center;
}

.card-expand-toggle[aria-expanded="true"] .card-expand-toggle__icon {
  transform: rotate(180deg);
}

/* Detail panel — hidden baseline via HTML `hidden` attribute */
.card-detail {
  overflow: hidden;
  max-height: 0;
  opacity: 0;
  padding: 0;
  border-top: 1px solid color-mix(in srgb, var(--accent-celeste) 20%, transparent);
  margin-top: 0;
  transition: max-height 0.35s ease, opacity 0.25s ease, padding 0.25s ease, margin-top 0.25s ease;
}

.card-detail[hidden] {
  display: none;
}

.card-detail--expanded {
  max-height: 40rem; /* generous cap — real content is 2-4 short paragraphs */
  opacity: 1;
  padding: 0.75rem 0 0;
  margin-top: 0.5rem;
}

.card-detail p {
  font-size: 0.875rem;
  line-height: 1.65;
  color: var(--text-secondary, color-mix(in srgb, var(--text) 85%, transparent));
  margin: 0 0 0.65rem;
}

.card-detail p:last-child {
  margin-bottom: 0;
}

/* ---- Responsive: expand/collapse at 320px ---- */
@media (max-width: 30rem) {
  .card-expand-toggle {
    font-size: 0.75rem;
  }

  .card-detail p {
    font-size: 0.825rem;
  }
}

/* ---- Accessibility: skip expand transition for reduced-motion users ---- */
@media (prefers-reduced-motion: reduce) {
  .card-expand-toggle__icon,
  .card-detail {
    transition: none;
  }
}

